-- Countries data
CREATE TABLE IF NOT EXISTS public.countries (
  id INTEGER PRIMARY KEY,
  name TEXT NOT NULL,
  iso3 TEXT,
  iso2 TEXT,
  numeric_code TEXT,
  phone_code TEXT,
  capital TEXT,
  currency TEXT,
  currency_name TEXT,
  currency_symbol TEXT,
  tld TEXT,
  native TEXT,
  region TEXT,
  subregion TEXT,
  timezones JSONB,
  translations JSONB,
  latitude DECIMAL(10, 8),
  longitude DECIMAL(11, 8),
  emoji TEXT,
  emoji_u TEXT
);

ON CONFLICT (id) DO NOTHING;

